/// <reference types="jest" />
import {
  buildDeploymentGuardPayload,
  buildDeploymentRegistrationPayload,
  normalizeDeploymentEnvironment,
  sanitizeDeploymentMetadata,
} from '../src/deployment-payload';
import { deploymentRegisteredIdempotencyKey } from '../src/idempotency';

describe('deployment payload utilities', () => {
  it('normalizes deployment environments', () => {
    expect(normalizeDeploymentEnvironment('prod')).toBe('production');
    expect(normalizeDeploymentEnvironment('staging')).toBe('staging');
  });

  it('prefers digest in deployment idempotency key', () => {
    const key = deploymentRegisteredIdempotencyKey({
      repository: 'org/api',
      workflowRunId: '42',
      runAttempt: '1',
      environment: 'production',
      artifactDigest: 'sha256:abc',
      deploymentName: 'fallback-name',
    });
    expect(key).toContain(':abc:');
    expect(key).not.toContain('fallback-name');
  });

  it('includes environment in idempotency key', () => {
    const prod = deploymentRegisteredIdempotencyKey({
      repository: 'org/api',
      workflowRunId: '42',
      runAttempt: '1',
      environment: 'production',
      artifactDigest: 'sha256:abc',
    });
    const staging = deploymentRegisteredIdempotencyKey({
      repository: 'org/api',
      workflowRunId: '42',
      runAttempt: '1',
      environment: 'staging',
      artifactDigest: 'sha256:abc',
    });
    expect(prod).not.toBe(staging);
  });

  it('builds registration payload with digest-first metadata', () => {
    const { body, warnings, mutableTagOnly } = buildDeploymentRegistrationPayload({
      environment: 'production',
      artifactDigest: 'sha256:' + 'a'.repeat(64),
      repository: 'org/api',
      workflowRunId: '99',
      releaseGateDecisionId: 'rg_1',
      correlationId: 'corr',
    });
    expect(body.artifactDigest).toMatch(/^sha256:/);
    expect(mutableTagOnly).toBe(false);
    expect(warnings).toHaveLength(0);
    expect((body.metadata as Record<string, unknown>).correlationId).toBe('corr');
  });

  it('warns on tag-only registration', () => {
    const { warnings, mutableTagOnly } = buildDeploymentRegistrationPayload({
      environment: 'staging',
      imageName: 'ghcr.io/org/api',
      imageTag: 'latest',
    });
    expect(mutableTagOnly).toBe(true);
    expect(warnings.some((w) => w.includes('mutable tag'))).toBe(true);
  });

  it('sanitizes sensitive metadata keys', () => {
    const out = sanitizeDeploymentMetadata({
      correlationId: 'ok',
      api_key: 'secret',
      deploymentUrl: 'https://example.com',
    });
    expect(out.api_key).toBeUndefined();
    expect(out.correlationId).toBe('ok');
  });

  it('guard payload includes enforcement mode', () => {
    const { body } = buildDeploymentGuardPayload({
      environment: 'production',
      artifactDigest: 'sha256:' + 'b'.repeat(64),
      enforcementMode: 'enforce',
    });
    expect(body.enforcementMode).toBe('enforce');
  });
});
